#nullable enable // autogenerated

using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Models;
using MVZ2.Vanilla.Entities;

using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;

using UnityEngine;

namespace MVZ2.GameContent.Buffs.Enemies
{
    [AutoBuffDefinition(VanillaBuffNames.Enemy.boat)]
    public class BoatBuff : BuffDefinition
    {
        public BoatBuff(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new IntModifier(VanillaEntityProps.WATER_INTERACTION, IntegerOperator.Set, WaterInteraction.FLOAT));
            AddModifier(new IntModifier(VanillaEntityProps.AIR_INTERACTION, IntegerOperator.Set, WaterInteraction.FLOAT));
            AddTrigger(LevelCallbacks.POST_ENTITY_DEATH, PostDeathCallback);
        }
        private void PostDeathCallback(LevelCallbacks.EntityDeathParams param, CallbackResult result)
        {
            var entity = param.entity;
            if (!entity.HasBuff<BoatBuff>())
                return;
            // �����鴬������
            entity.Level.Spawn(VanillaEffectID.brokenArmor, entity.GetCenter(), entity)?.Let(e =>
            {
                e.Velocity = new Vector3(e.RNG.NextFloat() * 20 - 10, 5, 0);
                e.ChangeModel(VanillaModelID.boatItem);
                e.SetDisplayScale(entity.GetDisplayScale());
            });
            entity.RemoveBuffs<BoatBuff>();
        }
    }
}
